func fieldValue(node ast.Node, name string) (reflect.Value, FieldSpec, error) {
	if node == nil {
		return reflect.Value{}, FieldSpec{}, fmt.Errorf("cannot access field %q on nil ast.Node", name)
	}
	nodeValue := reflect.ValueOf(node)
	if nodeValue.Kind() != reflect.Pointer || nodeValue.IsNil() {
		return reflect.Value{}, FieldSpec{}, fmt.Errorf("cannot access field %q on nil %T", name, node)
	}
	kind, ok := NodeKind(node)
	if !ok {
		return reflect.Value{}, FieldSpec{}, fmt.Errorf("unsupported ast.Node type %T", node)
	}
	nodeSpec := NodeSpecs[kind]
	var fieldSpec FieldSpec
	found := false
	for _, candidate := range nodeSpec.Fields {
		if candidate.Name == name {
			fieldSpec = candidate
			found = true
			break
		}
	}
	if !found {
		return reflect.Value{}, FieldSpec{}, fmt.Errorf("go/ast.%s has no included field %q", kind, name)
	}
	field := nodeValue.Elem().FieldByName(name)
	if !field.IsValid() || !field.CanInterface() {
		return reflect.Value{}, FieldSpec{}, fmt.Errorf("generated field metadata is stale for go/ast.%s.%s", kind, name)
	}
	return field, fieldSpec, nil
}

func GetNodeField(node ast.Node, name string) (any, error) {
	field, spec, err := fieldValue(node, name)
	if err != nil {
		return nil, err
	}
	switch spec.Kind {
	case "node":
		if field.IsNil() {
			return ast.Node(nil), nil
		}
		child, ok := field.Interface().(ast.Node)
		if !ok {
			return nil, fmt.Errorf("generated node field metadata is stale for %T.%s", node, name)
		}
		return child, nil
	case "node-list":
		if field.IsNil() {
			return []ast.Node(nil), nil
		}
		children := make([]ast.Node, field.Len())
		for index := 0; index < field.Len(); index++ {
			child, ok := field.Index(index).Interface().(ast.Node)
			if !ok {
				return nil, fmt.Errorf("generated node-list metadata is stale for %T.%s[%d]", node, name, index)
			}
			children[index] = child
		}
		return children, nil
	case "node-map":
		if field.IsNil() {
			return map[string]ast.Node(nil), nil
		}
		children := make(map[string]ast.Node, field.Len())
		iterator := field.MapRange()
		for iterator.Next() {
			child, ok := iterator.Value().Interface().(ast.Node)
			if !ok {
				return nil, fmt.Errorf("generated node-map metadata is stale for %T.%s[%q]", node, name, iterator.Key().String())
			}
			children[iterator.Key().String()] = child
		}
		return children, nil
	default:
		return field.Interface(), nil
	}
}

func SetNodeField(node ast.Node, name string, value any) error {
	field, spec, err := fieldValue(node, name)
	if err != nil {
		return err
	}
	if !field.CanSet() {
		return fmt.Errorf("cannot set %T.%s", node, name)
	}
	switch spec.Kind {
	case "node":
		if value == nil {
			field.Set(reflect.Zero(field.Type()))
			return nil
		}
		child, ok := value.(ast.Node)
		if !ok {
			return fmt.Errorf("%T.%s expects ast.Node, got %T", node, name, value)
		}
		return assignField(field, reflect.ValueOf(child), node, name)
	case "node-list":
		if value == nil {
			field.Set(reflect.Zero(field.Type()))
			return nil
		}
		children, ok := value.([]ast.Node)
		if !ok {
			return fmt.Errorf("%T.%s expects []ast.Node, got %T", node, name, value)
		}
		if children == nil {
			field.Set(reflect.Zero(field.Type()))
			return nil
		}
		target := reflect.MakeSlice(field.Type(), len(children), len(children))
		for index, child := range children {
			if child == nil {
				target.Index(index).Set(reflect.Zero(target.Index(index).Type()))
				continue
			}
			if err := assignField(target.Index(index), reflect.ValueOf(child), node, fmt.Sprintf("%s[%d]", name, index)); err != nil {
				return err
			}
		}
		field.Set(target)
		return nil
	case "node-map":
		if value == nil {
			field.Set(reflect.Zero(field.Type()))
			return nil
		}
		children, ok := value.(map[string]ast.Node)
		if !ok {
			return fmt.Errorf("%T.%s expects map[string]ast.Node, got %T", node, name, value)
		}
		if children == nil {
			field.Set(reflect.Zero(field.Type()))
			return nil
		}
		target := reflect.MakeMapWithSize(field.Type(), len(children))
		for key, child := range children {
			element := reflect.New(field.Type().Elem()).Elem()
			if child != nil {
				if err := assignField(element, reflect.ValueOf(child), node, fmt.Sprintf("%s[%q]", name, key)); err != nil {
					return err
				}
			}
			target.SetMapIndex(reflect.ValueOf(key), element)
		}
		field.Set(target)
		return nil
	default:
		if value == nil {
			return fmt.Errorf("%T.%s expects %s, got nil", node, name, field.Type())
		}
		source := reflect.ValueOf(value)
		if source.Type().AssignableTo(field.Type()) {
			field.Set(source)
			return nil
		}
		if source.Type().ConvertibleTo(field.Type()) {
			field.Set(source.Convert(field.Type()))
			return nil
		}
		return fmt.Errorf("%T.%s expects %s, got %T", node, name, field.Type(), value)
	}
}

func assignField(target, source reflect.Value, node ast.Node, name string) error {
	if source.IsValid() && source.Type().AssignableTo(target.Type()) {
		target.Set(source)
		return nil
	}
	return fmt.Errorf("%T.%s expects %s, got %s", node, name, target.Type(), source.Type())
}

type enumValueSpec struct {
	Name  string
	Value int64
}
type enumSpec struct {
	Flags  bool
	Values []enumValueSpec
}

var enumSpecs = map[string]enumSpec{
	"go/ast.ChanDir": {Flags: true, Values: []enumValueSpec{
		{Name: "SEND", Value: int64(ast.SEND)},
		{Name: "RECV", Value: int64(ast.RECV)},
	}},
}

func EnumNames(enumType string, value any) ([]string, error) {
	var raw int64
	switch enumType {
	case "go/ast.ChanDir":
		typed, ok := value.(ast.ChanDir)
		if !ok {
			return nil, fmt.Errorf("enum %s expects ast.ChanDir, got %T", enumType, value)
		}
		raw = int64(typed)
	default:
		return nil, fmt.Errorf("unknown enum type %q", enumType)
	}
	spec := enumSpecs[enumType]
	if !spec.Flags {
		for _, candidate := range spec.Values {
			if candidate.Value == raw {
				return []string{candidate.Name}, nil
			}
		}
		return nil, fmt.Errorf("enum %s has unknown value %d", enumType, raw)
	}
	remaining := raw
	names := make([]string, 0, len(spec.Values))
	for _, candidate := range spec.Values {
		if candidate.Value != 0 && remaining&candidate.Value == candidate.Value {
			names = append(names, candidate.Name)
			remaining &^= candidate.Value
		}
	}
	if remaining != 0 {
		return nil, fmt.Errorf("enum flags %s contain unknown bits %d", enumType, remaining)
	}
	return names, nil
}

func ParseEnum(enumType string, names []string) (any, error) {
	spec, ok := enumSpecs[enumType]
	if !ok {
		return nil, fmt.Errorf("unknown enum type %q", enumType)
	}
	if !spec.Flags && len(names) != 1 {
		return nil, fmt.Errorf("enum %s expects exactly one name", enumType)
	}
	byName := make(map[string]int64, len(spec.Values))
	for _, item := range spec.Values {
		byName[item.Name] = item.Value
	}
	seen := make(map[string]bool, len(names))
	var raw int64
	for _, name := range names {
		if seen[name] {
			return nil, fmt.Errorf("enum %s repeats name %q", enumType, name)
		}
		part, found := byName[name]
		if !found {
			return nil, fmt.Errorf("enum %s has no name %q", enumType, name)
		}
		seen[name] = true
		if spec.Flags {
			raw |= part
		} else {
			raw = part
		}
	}
	switch enumType {
	case "go/ast.ChanDir":
		return ast.ChanDir(raw), nil
	default:
		panic("unreachable enum type")
	}
}
